+function wikiToMarkdown(text: string, images: boolean): string {
+  const pattern = images ? /!\\[\\[([^\
\\]]+)\\]\\]/g : /(?<!!)\\[\\[([^\
\\]]+)\\]\\]/g;
+  return text.replace(pattern, (match, content: string) => {
+    const separator = content.indexOf('|');
+    const target = separator === -1 ? content : content.slice(0, separator);
+    let display = separator === -1 ? '' : content.slice(separator + 1);
+    if (images) {
+      if (display === '300' || display === '300x200') display = '';
+      return `![${display || target}](${target})`;
+    }
+    return `[${display || defaultHeadingDisplay(target)}](${target})`;
+  });
+}
+
+function markdownToWiki(text: string, images: boolean): string {
+  let result = '';
+  let position = 0;
+  while (position < text.length) {
+    const candidate = parseMarkdownLink(text, position);
+    if (!candidate || candidate.image !== images || candidate.destination.includes('://')) {
+      result += text[position++];
+      continue;
+    }
+    const target = candidate.destination;
+    const defaultDisplay = defaultHeadingDisplay(target);
+    let display = candidate.label;
+    if (images) {
+      result += `![[${target}${display === '' || display === target ? '' : `|${display}`}]]`;
+    } else {
+      if (display === target || display === defaultDisplay) display = '';
+      result += `[[${target}${display === '' ? '' : `|${display}`}]]`;
+    }
+    position = candidate.end;
+  }
+  return result;
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text[start] === '!';
+  const open = image ? start + 1 : start;
+  if (text[open] !== '[') return null;
+  const labelEnd = findBalancedEnd(text, open, '[', ']');
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') return null;
+  const parenEnd = findBalancedEnd(text, labelEnd + 1, '(', ')');
+  if (parenEnd === -1) return null;
+  const rawLabel = text.slice(open + 1, labelEnd);
+  const rawArea = text.slice(labelEnd + 2, parenEnd);
+  if (rawLabel.includes('\
') || rawArea.includes('\
')) return null;
+  const destination = parseDestination(rawArea);
+  if (destination === null) return null;
+  return {end: parenEnd + 1, image, label: unescapeMarkdown(rawLabel), destination};
+}
+
+function findBalancedEnd(text: string, open: number, opening: string, closing: string): number {
+  let depth = 0;
+  for (let index = open; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === opening) {
+      depth++;
+    } else if (text[index] === closing && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function parseDestination(area: string): string | null {
+  const trimmed = area.trim();
+  if (trimmed.startsWith('<')) {
+    if (!trimmed.endsWith('>') || hasUnescaped(trimmed.slice(1, -1), '>')) return null;
+    return unescapeMarkdown(trimmed.slice(1, -1));
+  }
+  // Whitespace here either makes the link invalid for this rule or begins a title.
+  for (let index = 0; index < trimmed.length; index++) {
+    if (/\\s/.test(trimmed[index]) && (index === 0 || trimmed[index - 1] !== '\\\')) return null;
+  }
+  return trimmed === '' ? null : unescapeMarkdown(trimmed);
+}
+
+function hasUnescaped(text: string, character: string): boolean {
+  for (let index = 0; index < text.length; index++) {
+    if (text[index] === '\\\') index++;
+    else if (text[index] === character) return true;
+  }
+  return false;
+}
+
+function unescapeMarkdown(text: string): string {
+  return text.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const hash = target.indexOf('#');
+  if (hash === -1) return target;
+  const page = target.slice(0, hash);
+  const heading = target.slice(hash + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
+}
